                  height: 220,
                  background: "#1a1a1a",
                  borderRadius: 8,
                  overflow: "hidden",
                  marginBottom: 8,
                }}
              >
                <img
                  src={oi.item.image_url}
                  alt={oi.item.title}
                  style={{
                    width: "100%",
                    height: "100%",
                    objectFit: "cover",
                  }}
                />
              </div>
              <p
                style={{
                  fontSize: 13,
                  margin: 0,
                  opacity: 0.9,
                  whiteSpace: "nowrap",
                  overflow: "hidden",
                  textOverflow: "ellipsis",
                }}
              >
                {oi.item.title}
              </p>
              <p style={{ fontSize: 13, margin: "4px 0 0", opacity: 0.6 }}>
                {oi.item.price}
              </p>
            </div>
          ))}
        </div>

        {/* Mira comment */}
        <p
          style={{
            fontSize: 15,
            fontStyle: "italic",
            opacity: 0.7,
            maxWidth: 600,
            textAlign: "center",
            margin: 0,
          }}
        >
          &ldquo;{outfit.mira_comment}&rdquo;
        </p>
      </div>

      {/* Navigation dots */}
      <div
        style={{
          display: "flex",
          justifyContent: "center",
          gap: 10,
          paddingTop: 20,
        }}
      >
        {outfits.map((_, i) => (
          <button
            key={i}
            onClick={() => onDotClick(i)}
            style={{
              width: 10,
              height: 10,
              borderRadius: "50%",
              border: "none",
              background: i === activeIndex ? "#fff" : "rgba(255,255,255,0.3)",
              cursor: "pointer",
              padding: 0,
            }}
          />
        ))}
      </div>
    </div>
  );
}

function ErrorView({ message }: { message: string }) {
  return (
    <div style={{ textAlign: "center", maxWidth: 500, padding: 40 }}>
      <p style={{ fontSize: 20, lineHeight: 1.6 }}>{message}</p>
    </div>
  );
}
